function reverseString(string) {
  let reversedString = "";
  for (let i = string.length - 1; i >= 0; i--) {
    reversedString += string[i];
  }
  return reversedString;
}

function sumArray(arr) { 
    if (arr.length === 0) { 
      return 0; 
    } 
    return arr[0] + sumArray(arr.slice(1)); 
} 
